    "schema_faq": "{\"@context\": \"https://schema.org\", \"@type\": \"FAQPage\", \"mainEntity\": [{\"@type\": \"Question\", \"name\": \"How much did X.ai sell for?\", \"acceptedAnswer\": {\"@type\": \"Answer\", \"text\": \"X.ai sold for $5 million in 2017.\"}}, {\"@type\": \"Question\", \"name\": \"Who bought X.ai?\", \"acceptedAnswer\": {\"@type\": \"Answer\", \"text\": \"Elon Musk linked entity / xAI branding ecosystem\"}}, {\"@type\": \"Question\", \"name\": \"Who sold X.ai?\", \"acceptedAnswer\": {\"@type\": \"Answer\", \"text\": \"Undisclosed\"}}, {\"@type\": \"Question\", \"name\": \"Why is X.ai valuable?\", \"acceptedAnswer\": {\"@type\": \"Answer\", \"text\": \"The name combines scarcity, memorability, AI relevance, and strategic brand value.\"}}, {\"@type\": \"Question\", \"name\": \"Where can I compare other .ai sales?\", \"acceptedAnswer\": {\"@type\": \"Answer\", \"text\": \"NameBuzz tracks notable .ai sales and publishes comparisons across premium transactions.\"}}]}",
